    (* Manual display output bits *)
    M06460 AT %M06460 : BOOL;
    M06461 AT %M06461 : BOOL;
    M06462 AT %M06462 : BOOL;
    M06463 AT %M06463 : BOOL;
    M06464 AT %M06464 : BOOL;
