    (* Manual SOL output *)
    M06910 AT %M06910 : BOOL; (* 수동 제품차단 SOL *)
    M06911 AT %M06911 : BOOL;
    M06912 AT %M06912 : BOOL; (* 수동 1차이송 SOL *)
    M06913 AT %M06913 : BOOL; (* 운전준비 완료 출력 *)
    M06914 AT %M06914 : BOOL; (* 수동 2차이송 후진 SOL *)
    M06915 AT %M06915 : BOOL;
    M06916 AT %M06916 : BOOL; (* 수동 2차이송 상승 SOL *)
    M06917 AT %M06917 : BOOL;
    M06918 AT %M06918 : BOOL; (* 수동 2차이송 회전복귀 SOL *)
    M06919 AT %M06919 : BOOL;
    M0691A AT %M0691A : BOOL; (* 수동 2차이송 클램프 SOL *)
    M0691B AT %M0691B : BOOL;
    M0691C AT %M0691C : BOOL; (* 수동 상부 SOL *)
    M0691D AT %M0691D : BOOL;
    M0691E AT %M0691E : BOOL; (* 수동 하부 SOL *)
    M0691F AT %M0691F : BOOL;
    M06920 AT %M06920 : BOOL; (* 수동 높이검사 SOL *)
    M06921 AT %M06921 : BOOL;
    M06922 AT %M06922 : BOOL; (* 수동 높이검사 상부 SOL *)
    M06923 AT %M06923 : BOOL;
    M06924 AT %M06924 : BOOL; (* 수동 추가제어 SOL *)
    M06925 AT %M06925 : BOOL;

    (* System bits *)
    M00010 AT %M00010 : BOOL; (* 자동 모드 *)
    M00011 AT %M00011 : BOOL; (* 수동 모드 *)
    M00012 AT %M00012 : BOOL; (* 자동 운전 정지 *)
    M00021 AT %M00021 : BOOL; (* 모든 유닛 초기위치 중 *)
    M00030 AT %M00030 : BOOL; (* EMO STOP 비상정지 *)
    M00053 AT %M00053 : BOOL; (* 서보 회전 중 *)
    M00075 AT %M00075 : BOOL; (* 코어 사이클스톱 *)
    M00176 AT %M00176 : BOOL; (* 코어 알람 *)
    M00180 AT %M00180 : BOOL; (* 알람 TOTAL *)
    M00304 AT %M00304 : BOOL; (* 자동 운전 상태 *)
    M00803 AT %M00803 : BOOL; (* 인덱스 서보 알람 *)
    M00840 AT %M00840 : BOOL; (* 도어오픈 ALARM *)
    M01106 AT %M01106 : BOOL; (* 코어 작업완료 *)
    M01116 AT %M01116 : BOOL; (* 코어 자재없음 *)
    M01115 AT %M01115 : BOOL; (* 코어 자재없음 보조 *)
    M01987 AT %M01987 : BOOL; (* 드라이런 관련 *)
    M0581A AT %M0581A : BOOL; (* 코어 불량 플래그 *)

    (* Main control bits *)
    M06000 AT %M06000 : BOOL; (* 코어 유닛 원점 완료 *)
    M06001 AT %M06001 : BOOL; (* 코어 자동 시작 조건 *)
    M06002 AT %M06002 : BOOL; (* 코어 자동 운전 중 *)
    M06004 AT %M06004 : BOOL; (* 코어 반자동 *)
    M06005 AT %M06005 : BOOL; (* 코어 초기위치 동작 *)
    M06251 AT %M06251 : BOOL; (* 코어 특수 스텝 플래그 *)
    M06300 AT %M06300 : BOOL; (* 코어 자재확인 트리거 *)
    M06301 AT %M06301 : BOOL; (* 코어 조립 완료 판정 *)

    (* Timers - ready operation *)
    TON_T0600 : TON; (* 반자동 지연 T#30ms *)
    TON_T0601 : TON; (* 반자동 지연2 T#20ms *)
    TON_T0611 : TON; (* 운전준비 스텝1 T#50ms *)
    TON_T0612 : TON; (* 운전준비 스텝2 T#50ms *)
    TON_T0613 : TON; (* 운전준비 스텝3 T#50ms *)
    TON_T0614 : TON; (* 운전준비 스텝4 T#50ms *)
    TON_T0615 : TON; (* 운전준비 스텝5 T#50ms *)
    TON_T0616 : TON; (* 운전준비 스텝6 T#50ms *)
    TON_T0617 : TON; (* 운전준비 스텝7 T#50ms *)
    TON_T0618 : TON; (* 운전준비 스텝8 T#50ms *)
    TON_T0619 : TON; (* 운전준비 스텝9 T#50ms *)

    (* Timers - auto sequence *)
    TON_T0621 : TON; (* 자동 스텝1  T#30ms *)
    TON_T0622 : TON; (* 자동 스텝2  T#50ms *)
    TON_T0623 : TON; (* 자동 스텝3  T#50ms *)
    TON_T0624 : TON; (* 자동 스텝4  T#50ms *)
    TON_T0625 : TON; (* 자동 스텝5  T#20ms *)
    TON_T0626 : TON; (* 자동 스텝6  T#20ms *)
    TON_T0627 : TON; (* 자동 스텝7  T#20ms *)
    TON_T0628 : TON; (* 자동 스텝8  T#20ms *)
    TON_T0629 : TON; (* 자동 스텝9  T#20ms *)
    TON_T0630 : TON; (* 자동 스텝10 T#20ms *)
    TON_T0631 : TON; (* 자동 스텝11 T#20ms *)
    TON_T0632 : TON; (* 자동 스텝12 T#20ms *)
    TON_T0633 : TON; (* 자동 스텝13 T#20ms *)
    TON_T0634 : TON; (* 자동 스텝14 T#20ms *)
    TON_T0635 : TON; (* 자동 스텝15 T#20ms *)
    TON_T0636 : TON; (* 자동 스텝16 T#20ms *)
    TON_T0637 : TON; (* 자동 스텝17 T#20ms *)
    TON_T0638 : TON; (* 자동 스텝18 T#20ms *)
    TON_T0639 : TON; (* 자동 스텝19 T#20ms *)
    TON_T0640 : TON; (* 자동 스텝20 T#20ms *)
    TON_T0641 : TON; (* 자동 스텝21 T#20ms *)
    TON_T0642 : TON; (* 자동 스텝22 T#100ms *)
    TON_T0643 : TON; (* 자동 스텝23 T#20ms *)
    TON_T0644 : TON; (* 자동 스텝24 T#20ms *)

    (* Data registers *)
    D00018 AT %D00018 : INT;  (* 인덱스 코어 스테이션 번호 *)
    D00600 AT %D00600 : INT;  (* 코어 운전준비 스텝 *)
    D00620 AT %D00620 : INT;  (* 코어 자동 운전 스텝 *)
    D07104 AT %D07104 : DINT; (* 검사 불량 카운트 *)

    T0013 AT %T0013 : BOOL;   (* 정지스위치 타이머 접점 *)

    (* Edge detection - XEC R_TRIG/F_TRIG standard *)
    R_TRIG_M06004  : R_TRIG;  (* 반자동 상승에지 *)
    R_TRIG_M06005  : R_TRIG;  (* 초기위치 상승에지 *)
    R_TRIG_M00021  : R_TRIG;  (* 초기위치완료 상승에지 *)
    R_TRIG_K00260  : R_TRIG;  (* HMI 반자동 터치 상승에지 *)
    R_TRIG_K00261  : R_TRIG;  (* HMI 초기위치 터치 상승에지 *)
    R_TRIG_K00112  : R_TRIG;  (* HMI 카운트리셋 상승에지 *)
    F_TRIG_F0009A  : F_TRIG;  (* F0009A _OFF 하강에지 *)
    K00260 AT %K00260 : BOOL; (* HMI 반자동 터치 *)
    K00261 AT %K00261 : BOOL; (* HMI 초기위치 터치 *)
    K00112 AT %K00112 : BOOL; (* HMI 불량카운트 리셋 터치 *)
    F00099 AT %F00099 : BOOL; (* 항상 ON 플래그 (_ON) *)
    F0009A AT %F0009A : BOOL; (* 항상 OFF 플래그 (_OFF) *)
END_VAR

(* ============================================================ *)
(* 섹션: 메인 (PAGE 82)                                         *)
(* ============================================================ *)

(* 래더 Line 0 - 코어 초기 SOL 출력 정의 (코일 선언 래더) *)
(* M06312, M06314, M06316, M06310, M06318, M0631A, M0631C *)
(* M0631E, M06320, M06913, M06000, M06319 → 후속 로직에서 제어 *)

(* 래더 Line 14 - 반자동 모드 시작 조건 *)
(* 자동모드(M00010) AND 코어알람없음(NOT M00176) AND 도어알람없음(NOT M00840) *)
(* AND 코어유닛상태(M06001) AND 사이클스톱없음(NOT M00075) AND 반자동비트(M06004) *)

(* 래더 Line 21 - 반자동 지연 타이머 *)
TON_T0600(IN := M06004, PT := T#30ms);

(* 래더 Line 24 - 반자동 진입 추가 조건 체크 *)
(* 자동모드 AND 코어알람없음 AND 알람TOTAL없음 AND D00620<>0 AND M00075없음 *)

(* 래더 Line 31 - 반자동 SET: 수동+반자동비트+T0600만료 → K00260 상승에지 *)
R_TRIG_K00260(CLK := K00260);
IF M00011 AND M06004 AND TON_T0600.Q AND R_TRIG_K00260.Q THEN
    M06002 := TRUE;  (* 코어 자동 운전 SET *)
    M00803 := TRUE;  (* 인덱스 서보 알람 SET *)
END_IF;

(* 래더 Line 37 - 자동모드+코어알람 조건 *)
IF M00010 AND M00176 THEN
    (* 알람 상태 처리 - 후속 래더에서 제어 *)
END_IF;

(* 래더 Line 41 - 반자동 해제 타이머 *)
TON_T0601(IN := M06002, PT := T#20ms);

(* 래더 Line 44 - 반자동 RST: T0601만료 AND 반자동비트 → K00260 상승에지 *)
R_TRIG_K00260(CLK := K00260);
IF TON_T0601.Q AND M06004 AND M00011 AND R_TRIG_K00260.Q THEN
    M06002 := FALSE; (* 코어 자동 운전 RST *)
END_IF;

(* 래더 Line 51 - 초기위치 동작 조건: M06004 OR M06002 → M06005 *)
M06005 := M06004 OR M06002;

(* 래더 Line 54 - 초기위치 이동 시작 조건 에지 *)
R_TRIG_M06005(CLK := M06005);
R_TRIG_M00021(CLK := M00021);

IF M06005 AND M00021 AND M00010 THEN
    R_TRIG_M00021(CLK := M00021);
    IF R_TRIG_M00021.Q THEN
        (* 초기위치 완료 상승에지 처리 *)
    END_IF;
END_IF;

(* 래더 Line 71 - 반자동 완료 → 코어 반자동 SET *)
(* 수동 AND 코어유닛상태 → K00260 P(상승에지) *)
R_TRIG_K00260(CLK := K00260);
IF M00011 AND M06000 AND R_TRIG_K00260.Q THEN
    M06004 := TRUE; (* 코어 반자동 SET *)
    D00018 := 1;    (* MOV 1 → D00018: 코어 스테이션 번호 *)
END_IF;

(* 래더 Line 78 - 반자동 완료 후 리셋 조건 *)
(* M06004 AND M06218 AND M01106 AND M0631C AND M06320 → K00261 P *)
R_TRIG_K00261(CLK := K00261);
IF M06004 AND M06218 AND M01106 AND M0631C AND M06320 THEN
    M06004 := FALSE;  (* 코어 반자동 RST *)
    M06002 := FALSE;  (* 코어 자동 운전 RST *)
    IF R_TRIG_K00261.Q THEN
        D00018 := 0;  (* MOVP 0 → D00018 *)
    END_IF;
    M00304 := TRUE;   (* 자동 운전 상태 SET *)
END_IF;

(* 래더 Line 93 - 초기위치 완료: 수동 AND 코어유닛상태 → K00261 P *)
R_TRIG_K00261(CLK := K00261);
IF M00011 AND M06000 AND R_TRIG_K00261.Q THEN
    M06005 := TRUE;   (* 코어 초기위치 SET *)
    R_TRIG_M00021(CLK := M00021);
    (* M00021 상승에지 처리 *)
END_IF;

(* 래더 Line 101 - 초기위치 완료 처리 *)
IF M06000 AND M06010 THEN
    M06005 := FALSE;  (* 코어 초기위치 RST *)
END_IF;
F_TRIG_F0009A(CLK := F0009A);
IF M00011 AND NOT M00030 AND M00304 AND F_TRIG_F0009A.Q THEN
    (* _OFF 하강에지 처리 *)
END_IF;

(* ============================================================ *)
(* 섹션: 운전 준비 - D00600 CASE문 (PAGE 83)                   *)
(* ============================================================ *)

(* 래더 Line 110 - 운전준비 스텝 DECO: DECO D00600 → M0601x (4비트) *)
(* XEC: 등가 비교 방식으로 변환 *)
M06010 := (D00600 = 0);
